export function getModelAnalysis(slug: string, locale: string = 'ja'): ModelAnalysis | undefined {
  if (locale === 'en') return modelAnalysesEn[slug] || modelAnalysesJa[slug];
  return modelAnalysesJa[slug] || modelAnalysesEn[slug];
}
